package com.travelassistant.consultation;import com.travelassistant.consultation.api.ConsultationDtos.*;import java.util.*;import org.springframework.stereotype.Component;
@Component public class ConversationMapper{public MessageView message(Message m){return new MessageView(m.getId(),m.getRole(),m.getContent(),m.getStatus(),m.getTripVersion()==null?null:m.getTripVersion().getVersionNumber(),m.getModel(),new Usage(m.getInputTokens(),m.getOutputTokens()),m.getErrorCode(),m.getCreatedAt().toString(),m.getCompletedAt()==null?null:m.getCompletedAt().toString());}public ConversationView conversation(Conversation c,List<Message>messages){return new ConversationView(c.getId(),c.getTitle(),c.getTrip()==null?null:c.getTrip().getId(),c.getCreatedAt().toString(),c.getUpdatedAt().toString(),messages.stream().filter(m->m.getRole()!=MessageRole.SYSTEM).map(this::message).toList());}public ConversationSummary summary(Conversation c){return new ConversationSummary(c.getId(),c.getTitle(),c.getTrip()==null?null:c.getTrip().getId(),c.getUpdatedAt().toString());}}
